	mkdirSync(dataDir, { recursive: true });

	// Find a free port by briefly binding
	const tempServer = Bun.serve({ port: 0, hostname: "127.0.0.1", fetch: () => new Response("") });
	apiPort = tempServer.port;
	tempServer.stop(true);

	apiBaseUrl = `http://localhost:${apiPort}`;

	// Start real API server with test PORT and working directory
	const apiEntrypoint = join(import.meta.dir, "..", "..", "..", "..", "api", "src", "index.ts");
	apiProcess = Bun.spawn(["bun", apiEntrypoint], {
		env: {
			...process.env,
			PORT: String(apiPort),
		},
		cwd: tempDir,
		stdout: "pipe",
		stderr: "pipe",
	});

	// Wait for server to be ready
	await waitForServer(`${apiBaseUrl}/rpc/health`, 15_000);

	// Create a test user via sign-up and extract session token
	const signupResponse = await fetch(`${apiBaseUrl}/api/auth/sign-up/email`, {
		method: "POST",
		headers: { "Content-Type": "application/json" },
		body: JSON.stringify({
			name: "Test User",
			email: "test@example.com",
			password: "testpassword123",
		}),
	});

	expect(signupResponse.ok).toBe(true);

	// Extract session token from set-cookie header
	const cookies = signupResponse.headers.getSetCookie();
	const sessionCookie = cookies.find((c) => c.startsWith("better-auth.session_token="));
	expect(sessionCookie).toBeDefined();
	sessionToken = sessionCookie!.split("=")[1]!.split(";")[0]!;
