import {
	afterAll,
	beforeAll,
	describe,
	expect,
	setDefaultTimeout,
	test,
} from "bun:test";

setDefaultTimeout(30_000);
import type { Subprocess } from "bun";
import { mkdirSync, mkdtempSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { clearCredentials, loadCredentials, saveCredentials } from "../lib/credentials.js";

let apiProcess: Subprocess;
let apiPort: number;
let apiBaseUrl: string;
let tempDir: string;
let configDir: string;
let sessionToken: string;

async function waitForServer(url: string, timeoutMs = 10_000): Promise<void> {
	const deadline = Date.now() + timeoutMs;
	while (Date.now() < deadline) {
		try {
			const res = await fetch(url, {
				method: "POST",
				headers: { "Content-Type": "application/json" },
				body: "{}",
			});
			if (res.ok) return;
		} catch {
			// not ready yet
		}
		await Bun.sleep(100);
	}
	throw new Error(`Server at ${url} did not start within ${timeoutMs}ms`);
}

beforeAll(async () => {
	// Create temp directories
	tempDir = mkdtempSync(join(tmpdir(), "rudel-auth-test-"));
	configDir = join(tempDir, "config");
	mkdirSync(configDir, { recursive: true });

	// Create data dir for SQLite DB
	const dataDir = join(tempDir, "data");
	mkdirSync(dataDir, { recursive: true });

	// Find a free port by briefly binding
	const tempServer = Bun.serve({ port: 0, hostname: "127.0.0.1", fetch: () => new Response("") });
	apiPort = tempServer.port as number;
	tempServer.stop(true);

	apiBaseUrl = `http://localhost:${apiPort}`;

	// Start real API server with test PORT and working directory
	const apiEntrypoint = join(import.meta.dir, "..", "..", "..", "api", "src", "index.ts");
	apiProcess = Bun.spawn(["bun", apiEntrypoint], {
		env: {
			...process.env,
			PORT: String(apiPort),
		},
		cwd: tempDir,
		stdout: "ignore",
		stderr: "ignore",
	});

	// Wait for server to be ready
