async function readAvailable(stream: ReadableStream<Uint8Array>): Promise<Uint8Array | null> {
	const reader = stream.getReader();
	try {
		// Use a short timeout to make this non-blocking
		const result = await Promise.race([
			reader.read(),
			Bun.sleep(10).then(() => ({ value: undefined, done: false })),
		]);
		if (result.value) return result.value;
		return null;
	} finally {
		reader.releaseLock();
	}
}

// Helpers that operate on a specific config dir (matching the RUDEL_CONFIG_DIR env var)
function saveCredentialsToDir(dir: string, token: string, apiBaseUrl: string): void {
	const { writeFileSync } = require("node:fs");
	writeFileSync(
		join(dir, "credentials.json"),
		JSON.stringify({ token, apiBaseUrl }, null, 2),
		{ mode: 0o600 },
	);
}

function loadCredentialsFromDir(dir: string): { token: string; apiBaseUrl: string } | null {
	const path = join(dir, "credentials.json");
	try {
		const { readFileSync } = require("node:fs");
		const content = readFileSync(path, "utf-8");
		return JSON.parse(content);
	} catch {
		return null;
	}
}

function clearCredentialsFromDir(dir: string): void {
	const path = join(dir, "credentials.json");
	try {
		const { rmSync } = require("node:fs");
		rmSync(path);
	} catch {
		// already gone
	}
}

