     3→export interface UploadConfig {
     4→	endpoint: string;
     5→	apiKey: string;
     6→}
     7→
     8→/**
     9→ * Upload a session transcript to the backend endpoint.
    10→ */
    11→export async function uploadSession(
    12→	request: IngestRequest,
    13→	config: UploadConfig,
    14→): Promise<UploadResult> {
    15→	try {
    16→		const response = await fetch(config.endpoint, {
    17→			method: "POST",
    18→			headers: {
    19→				"Content-Type": "application/json",
    20→				"x-api-key": config.apiKey,
    21→			},
    22→			body: JSON.stringify(request),
    23→		});
    24→
    25→		const responseText = await response.text();
    26→
    27→		if (!response.ok) {
    28→			return {
    29→				success: false,
    30→				status: response.status,
    31→				error: `HTTP ${response.status}: ${responseText}`,
    32→			};
    33→		}
    34→
    35→		return { success: true, status: response.status };
    36→	} catch (error) {
    37→		return { success: false, error: String(error) };
    38→	}
    39→}
