     1→import { RPCHandler } from "@orpc/server/fetch";
     2→import { auth } from "./auth.js";
     3→import { router } from "./router.js";
     4→
     5→const rpcHandler = new RPCHandler(router);
     6→
     7→const ALLOWED_ORIGIN = "http://localhost:4011";
     8→
     9→function corsHeaders(origin: string | null): Record<string, string> {
    10→	if (origin !== ALLOWED_ORIGIN) return {};
    11→	return {
    12→		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
    13→		"Access-Control-Allow-Credentials": "true",
    14→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
    15→		"Access-Control-Allow-Headers": "Content-Type, Authorization",
    16→	};
    17→}
    18→
    19→const port = process.env.PORT ?? 4010;
    20→
    21→Bun.serve({
    22→	port,
    23→	async fetch(request) {
    24→		const origin = request.headers.get("Origin");
    25→		const cors = corsHeaders(origin);
    26→
    27→		if (request.method === "OPTIONS") {
    28→			return new Response(null, { status: 204, headers: cors });
    29→		}
    30→
    31→		const url = new URL(request.url);
    32→
    33→		if (url.pathname.startsWith("/api/auth")) {
    34→			const response = await auth.handler(request);
    35→			for (const [key, value] of Object.entries(cors)) {
    36→				response.headers.set(key, value);
    37→			}
    38→			return response;
    39→		}
    40→
    41→		const { matched, response } = await rpcHandler.handle(request, {
    42→			prefix: "/rpc",
    43→			context: await getContext(request),
    44→		});
    45→
    46→		if (matched) {
    47→			for (const [key, value] of Object.entries(cors)) {
    48→				response.headers.set(key, value);
    49→			}
    50→			return response;
    51→		}
    52→
    53→		return new Response("Not found", { status: 404, headers: cors });
    54→	},
    55→});
    56→
    57→async function getContext(request: Request) {
    58→	const session = await auth.api.getSession({
    59→		headers: request.headers,
    60→	});
    61→	return {
    62→		user: session?.user ?? null,
    63→		session: session?.session ?? null,
    64→	};
    65→}
    66→
