    16→async function runUpload(
    17→	flags: {
    18→		tag?: SessionTag;
    19→		endpoint: string;
    20→		apiKey?: string;
    21→		classify: boolean;
    22→		dryRun: boolean;
    23→	},
    24→	session: string,
    25→): Promise<void> {
    26→	const write = (msg: string) => {
    27→		process.stdout.write(`${msg}\n`);
    28→	};
    29→	const writeError = (msg: string) => {
    30→		process.stderr.write(`${msg}\n`);
    31→	};
    32→
    33→	// Resolve API key
    34→	const apiKey = flags.apiKey ?? process.env.FLICK_COMPOUND_API_KEY;
    35→	if (!apiKey && !flags.dryRun) {
    36→		writeError(
    37→			"Error: API key required. Set FLICK_COMPOUND_API_KEY or use --api-key",
    38→		);
    39→		process.exitCode = 1;
    40→		return;
    41→	}
    42→
    43→	// Resolve session (by ID or path)
    44→	write(`Resolving session: ${session}`);
    45→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
    46→	try {
