    57→	// Read transcript
    58→	write("Reading transcript...");
    59→	let content: string;
    60→	try {
    61→		content = await readTranscript(sessionInfo.transcriptPath);
    62→	} catch (error) {
    63→		writeError(
    64→			`Error reading transcript: ${error instanceof Error ? error.message : String(error)}`,
    65→		);
    66→		process.exitCode = 1;
    67→		return;
    68→	}
    69→	write(`Transcript: ${content.length} bytes`);
    70→
    71→	// Extract and read subagents
    72→	const agentIds = extractAgentIds(content);
    73→	let subagents: SubagentFile[] = [];
    74→	if (agentIds.length > 0) {
    75→		write(`Found ${agentIds.length} subagent(s): ${agentIds.join(", ")}`);
    76→		subagents = await readSubagentFiles(
    77→			sessionInfo.sessionDir,
    78→			agentIds,
    79→			sessionInfo.sessionId,
    80→		);
    81→		write(
    82→			`Read ${subagents.length} subagent file(s): ${subagents.reduce((sum, s) => sum + s.content.length, 0)} bytes total`,
    83→		);
    84→	}
    85→
    86→	// Get git info
    87→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
    88→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
    89→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
    90→
    91→	// Classify if requested
    92→	let tag = flags.tag;
    93→	if (!tag && flags.classify) {
    94→		write("Classifying session...");
    95→		tag = (await classifySession(content)) ?? undefined;
    96→		if (tag) write(`Classified as: ${tag}`);
    97→	}
    98→
    99→	// Build request
   100→	const request: IngestRequest = {
   101→		sessionId: sessionInfo.sessionId,
   102→		projectPath: sessionInfo.projectPath,
   103→		repository: gitInfo.repository,
   104→		gitBranch: gitInfo.branch,
   105→		gitSha: gitInfo.sha,
   106→		tag,
   107→		content,
   108→		subagents: subagents.length > 0 ? subagents : undefined,
   109→	};
   110→
   111→	// Upload or dry-run
   112→	if (flags.dryRun) {
   113→		const preview = {
   114→			...request,
   115→			content: `[${request.content.length} bytes]`,
   116→			subagents: request.subagents?.map((s) => ({
   117→				...s,
   118→				content: `[${s.content.length} bytes]`,
   119→			})),
   120→		};
   121→		write("Dry run - would upload:");
   122→		write(JSON.stringify(preview, null, 2));
   123→		return;
   124→	}
   125→
   126→	write("Uploading...");
   127→	const result = await uploadSession(request, {
   128→		endpoint: flags.endpoint,
   129→		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
   130→		apiKey: apiKey!,
   131→	});
   132→
   133→	if (result.success) {
   134→		write("Upload successful!");
   135→	} else {
   136→		writeError(`Upload failed: ${result.error}`);
   137→		process.exitCode = 1;
   138→	}
   139→}
