    22→	const deadline = Date.now() + timeoutMs;
    23→	while (Date.now() < deadline) {
    24→		try {
    25→			const res = await fetch(url, {
    26→				method: "POST",
    27→				headers: { "Content-Type": "application/json" },
    28→				body: "{}",
    29→			});
    30→			if (res.ok) return;
    31→		} catch {
    32→			// not ready yet
    33→		}
    34→		await Bun.sleep(100);
    35→	}
    36→	throw new Error(`Server at ${url} did not start within ${timeoutMs}ms`);
    37→}
