   242→// Helpers that operate on a specific config dir (matching the RUDEL_CONFIG_DIR env var)
   243→function saveCredentialsToDir(dir: string, token: string, apiBaseUrl: string): void {
   244→	const { writeFileSync } = require("node:fs");
   245→	writeFileSync(
   246→		join(dir, "credentials.json"),
   247→		JSON.stringify({ token, apiBaseUrl }, null, 2),
   248→		{ mode: 0o600 },
   249→	);
   250→}
   251→
   252→function loadCredentialsFromDir(dir: string): { token: string; apiBaseUrl: string } | null {
   253→	const path = join(dir, "credentials.json");
   254→	try {
   255→		const { readFileSync } = require("node:fs");
   256→		const content = readFileSync(path, "utf-8");
   257→		return JSON.parse(content);
   258→	} catch {
   259→		return null;
   260→	}
   261→}
   262→
   263→function clearCredentialsFromDir(dir: string): void {
